    27→var supportedTags = []string{
    28→	"genclient",
    29→	"genclient:nonNamespaced",
    30→	"genclient:noVerbs",
    31→	"genclient:onlyVerbs",
    32→	"genclient:skipVerbs",
    33→	"genclient:noStatus",
    34→	"genclient:readonly",
    35→	"genclient:method",
    36→}
    37→
    38→// SupportedVerbs is a list of supported verbs for +onlyVerbs and +skipVerbs.
    39→var SupportedVerbs = []string{
    40→	"create",
    41→	"update",
    42→	"updateStatus",
    43→	"delete",
    44→	"deleteCollection",
    45→	"get",
    46→	"list",
    47→	"watch",
    48→	"patch",
    49→	"apply",
    50→	"applyStatus",
    51→}
    52→
    53→// ReadonlyVerbs represents a list of read-only verbs.
    54→var ReadonlyVerbs = []string{
    55→	"get",
    56→	"list",
    57→	"watch",
    58→}
    59→
    60→// genClientPrefix is the default prefix for all genclient tags.
    61→const genClientPrefix = "genclient:"
    62→
    63→// unsupportedExtensionVerbs is a list of verbs we don't support generating
    64→// extension client functions for.
    65→var unsupportedExtensionVerbs = []string{
    66→	"updateStatus",
    67→	"deleteCollection",
    68→	"watch",
    69→	"delete",
    70→}
    71→
    72→// inputTypeSupportedVerbs is a list of verb types that supports overriding the
    73→// input argument type.
    74→var inputTypeSupportedVerbs = []string{
    75→	"create",
    76→	"update",
    77→	"apply",
    78→}
    79→
    80→// resultTypeSupportedVerbs is a list of verb types that supports overriding the
    81→// resulting type.
    82→var resultTypeSupportedVerbs = []string{
    83→	"create",
    84→	"update",
    85→	"get",
    86→	"list",
    87→	"patch",
    88→	"apply",
    89→}
    90→
    91→// Extensions allows to extend the default set of client verbs
    92→// (CRUD+watch+patch+list+deleteCollection) for a given type with custom defined
    93→// verbs. Custom verbs can have custom input and result types and also allow to
    94→// use a sub-resource in a request instead of top-level resource type.
    95→//
    96→// Example:
    97→//
    98→// +genclient:method=UpdateScale,verb=update,subresource=scale,input=Scale,result=Scale
    99→//
   100→// type ReplicaSet struct { ... }
   101→//
   102→// The 'method=UpdateScale' is the name of the client function.
   103→// The 'verb=update' here means the client function will use 'PUT' action.
   104→// The 'subresource=scale' means we will use SubResource template to generate this client function.
   105→// The 'input' is the input type used for creation (function argument).
   106→// The 'result' (not needed in this case) is the result type returned from the
   107→// client function.
   108→type extension struct {
   109→	// VerbName is the name of the custom verb (Scale, Instantiate, etc..)
   110→	VerbName string
   111→	// VerbType is the type of the verb (only verbs from SupportedVerbs are
   112→	// supported)
   113→	VerbType string
   114→	// SubResourcePath defines a path to a sub-resource to use in the request.
   115→	// (optional)
   116→	SubResourcePath string
   117→	// InputTypeOverride overrides the input parameter type for the verb. By
   118→	// default the original type is used. Overriding the input type only works for
   119→	// "create" and "update" verb types. The given type must exists in the same
   120→	// package as the original type.
   121→	// (optional)
   122→	InputTypeOverride string
   123→	// ResultTypeOverride overrides the resulting object type for the verb. By
   124→	// default the original type is used. Overriding the result type works.
   125→	// (optional)
   126→	ResultTypeOverride string
   127→}
   128→
   129→// IsSubresource indicates if this extension should generate the sub-resource.
   130→func (e *extension) IsSubresource() bool {
   131→	return len(e.SubResourcePath) > 0
   132→}
   133→
   134→// HasVerb checks if the extension matches the given verb.
   135→func (e *extension) HasVerb(verb string) bool {
   136→	return e.VerbType == verb
   137→}
   138→
   139→// Input returns the input override package path and the type.
   140→func (e *extension) Input() (string, string) {
   141→	parts := strings.Split(e.InputTypeOverride, ".")
   142→	return parts[len(parts)-1], strings.Join(parts[0:len(parts)-1], ".")
   143→}
   144→
   145→// Result returns the result override package path and the type.
   146→func (e *extension) Result() (string, string) {
   147→	parts := strings.Split(e.ResultTypeOverride, ".")
   148→	return parts[len(parts)-1], strings.Join(parts[0:len(parts)-1], ".")
   149→}
   150→
   151→// Tags represents a genclient configuration for a single type.
   152→type Tags struct {
   153→	// +genclient
   154→	GenerateClient bool
   155→	// +genclient:nonNamespaced
   156→	NonNamespaced bool
   157→	// +genclient:noStatus
   158→	NoStatus bool
   159→	// +genclient:noVerbs
   160→	NoVerbs bool
   161→	// +genclient:skipVerbs=get,update
   162→	// +genclient:onlyVerbs=create,delete
   163→	SkipVerbs []string
   164→	// +genclient:method=UpdateScale,verb=update,subresource=scale,input=Scale,result=Scale
   165→	Extensions []extension
   166→}
   167→
   168→// HasVerb returns true if we should include the given verb in final client interface and
   169→// generate the function for it.
   170→func (t Tags) HasVerb(verb string) bool {
   171→	if len(t.SkipVerbs) == 0 {
   172→		return true
   173→	}
   174→	for _, s := range t.SkipVerbs {
   175→		if verb == s {
   176→			return false
   177→		}
   178→	}
   179→	return true
   180→}
   181→
   182→// MustParseClientGenTags calls ParseClientGenTags but instead of returning error it panics.
   183→func MustParseClientGenTags(lines []string) Tags {
   184→	tags, err := ParseClientGenTags(lines)
   185→	if err != nil {
   186→		panic(err.Error())
   187→	}
   188→	return tags
   189→}
   190→
   191→// ParseClientGenTags parse the provided genclient tags and validates that no unknown
   192→// tags are provided.
   193→func ParseClientGenTags(lines []string) (Tags, error) {
   194→	ret := Tags{}
   195→	values := gengo.ExtractCommentTags("+", lines)
   196→	var value []string
   197→	value, ret.GenerateClient = values["genclient"]
   198→	// Check the old format and error when used to avoid generating client when //+genclient=false
   199→	if len(value) > 0 && len(value[0]) > 0 {
   200→		return ret, fmt.Errorf("+genclient=%s is invalid, use //+genclient if you want to generate client or omit it when you want to disable generation", value)
   201→	}
   202→	_, ret.NonNamespaced = values[genClientPrefix+"nonNamespaced"]
   203→	// Check the old format and error when used
   204→	if value := values["nonNamespaced"]; len(value) > 0 && len(value[0]) > 0 {
   205→		return ret, fmt.Errorf("+nonNamespaced=%s is invalid, use //+genclient:nonNamespaced instead", value[0])
   206→	}
   207→	_, ret.NoVerbs = values[genClientPrefix+"noVerbs"]
   208→	_, ret.NoStatus = values[genClientPrefix+"noStatus"]
   209→	onlyVerbs := []string{}
   210→	if _, isReadonly := values[genClientPrefix+"readonly"]; isReadonly {
   211→		onlyVerbs = ReadonlyVerbs
   212→	}
   213→	// Check the old format and error when used
   214→	if value := values["readonly"]; len(value) > 0 && len(value[0]) > 0 {
   215→		return ret, fmt.Errorf("+readonly=%s is invalid, use //+genclient:readonly instead", value[0])
   216→	}
   217→	if v, exists := values[genClientPrefix+"skipVerbs"]; exists {
   218→		ret.SkipVerbs = strings.Split(v[0], ",")
   219→	}
   220→	if v, exists := values[genClientPrefix+"onlyVerbs"]; exists || len(onlyVerbs) > 0 {
   221→		if len(v) > 0 {
   222→			onlyVerbs = append(onlyVerbs, strings.Split(v[0], ",")...)
   223→		}
   224→		skipVerbs := []string{}
   225→		for _, m := range SupportedVerbs {
   226→			skip := true
   227→			for _, o := range onlyVerbs {
   228→				if o == m {
   229→					skip = false
   230→					break
   231→				}
   232→			}
   233→			// Check for conflicts
   234→			for _, v := range skipVerbs {
   235→				if v == m {
   236→					return ret, fmt.Errorf("verb %q used both in genclient:skipVerbs and genclient:onlyVerbs", v)
   237→				}
   238→			}
   239→			if skip {
   240→				skipVerbs = append(skipVerbs, m)
   241→			}
   242→		}
   243→		ret.SkipVerbs = skipVerbs
   244→	}
   245→	var err error
   246→	if ret.Extensions, err = parseClientExtensions(values); err != nil {
   247→		return ret, err
   248→	}
   249→	return ret, validateClientGenTags(values)
   250→}
   251→
   252→func parseClientExtensions(tags map[string][]string) ([]extension, error) {
   253→	var ret []extension
   254→	for name, values := range tags {
   255→		if !strings.HasPrefix(name, genClientPrefix+"method") {
   256→			continue
   257→		}
   258→		for _, value := range values {
   259→			// the value comes in this form: "Foo,verb=create"
   260→			ext := extension{}
   261→			parts := strings.Split(value, ",")
   262→			if len(parts) == 0 {
   263→				return nil, fmt.Errorf("invalid of empty extension verb name: %q", value)
   264→			}
   265→			// The first part represents the name of the extension
   266→			ext.VerbName = parts[0]
   267→			if len(ext.VerbName) == 0 {
   268→				return nil, fmt.Errorf("must specify a verb name (// +genclient:method=Foo,verb=create)")
   269→			}
   270→			// Parse rest of the arguments
   271→			params := parts[1:]
   272→			for _, p := range params {
   273→				parts := strings.Split(p, "=")
   274→				if len(parts) != 2 {
   275→					return nil, fmt.Errorf("invalid extension tag specification %q", p)
   276→				}
   277→				key, val := strings.TrimSpace(parts[0]), strings.TrimSpace(parts[1])
   278→				if len(val) == 0 {
   279→					return nil, fmt.Errorf("empty value of %q for %q extension", key, ext.VerbName)
   280→				}
   281→				switch key {
   282→				case "verb":
   283→					ext.VerbType = val
   284→				case "subresource":
   285→					ext.SubResourcePath = val
   286→				case "input":
   287→					ext.InputTypeOverride = val
   288→				case "result":
   289→					ext.ResultTypeOverride = val
   290→				default:
   291→					return nil, fmt.Errorf("unknown extension configuration key %q", key)
   292→				}
   293→			}
   294→			// Validate resulting extension configuration
   295→			if len(ext.VerbType) == 0 {
   296→				return nil, fmt.Errorf("verb type must be specified (use '// +genclient:method=%s,verb=create')", ext.VerbName)
   297→			}
   298→			if len(ext.ResultTypeOverride) > 0 {
   299→				supported := false
   300→				for _, v := range resultTypeSupportedVerbs {
   301→					if ext.VerbType == v {
   302→						supported = true
   303→						break
   304→					}
   305→				}
   306→				if !supported {
   307→					return nil, fmt.Errorf("%s: result type is not supported for %q verbs (supported verbs: %#v)", ext.VerbName, ext.VerbType, resultTypeSupportedVerbs)
   308→				}
   309→			}
   310→			if len(ext.InputTypeOverride) > 0 {
   311→				supported := false
   312→				for _, v := range inputTypeSupportedVerbs {
   313→					if ext.VerbType == v {
   314→						supported = true
   315→						break
   316→					}
   317→				}
   318→				if !supported {
   319→					return nil, fmt.Errorf("%s: input type is not supported for %q verbs (supported verbs: %#v)", ext.VerbName, ext.VerbType, inputTypeSupportedVerbs)
   320→				}
   321→			}
   322→			for _, t := range unsupportedExtensionVerbs {
   323→				if ext.VerbType == t {
   324→					return nil, fmt.Errorf("verb %q is not supported by extension generator", ext.VerbType)
   325→				}
   326→			}
   327→			ret = append(ret, ext)
   328→		}
   329→	}
   330→	return ret, nil
   331→}
   332→
   333→// validateTags validates that only supported genclient tags were provided.
   334→func validateClientGenTags(values map[string][]string) error {
   335→	for _, k := range supportedTags {
   336→		delete(values, k)
   337→	}
   338→	for key := range values {
   339→		if strings.HasPrefix(key, strings.TrimSuffix(genClientPrefix, ":")) {
   340→			return errors.New("unknown tag detected: " + key)
   341→		}
   342→	}
   343→	return nil
   344→}
